using System;
using Microsoft.Data.SqlClient; //Install-Package Microsoft.Data.SqlClient

public class DBConnectionHelper
{
    private readonly string _connectionString = "Server=localhost;Database=HackathonDB;User Id=sa;Password=DevPass123!;";

    public SqlConnection Connection { get; set; }
    
    public bool Open()
    {
        try
        {
            this.Connection = new SqlConnection(_connectionString); // Initialize connection
            
            this.Connection.Open(); // open the connection
            return true;
        }
        catch (SqlException e)
        {
            Console.WriteLine("Could not connect to database");
            Console.WriteLine(e.ToString());
            return false;
        }
    }
    
    public bool Close()
    {
        try
        {
            this.Connection?.Close(); // close the connection if it exists
            return true;
        }
        catch (SqlException e)
        {
            Console.WriteLine("Could not disconnect from database");
            Console.WriteLine(e.ToString());
            return false;
        }
    }
}
